#!/usr/bin/env python3
"""Compute and print the first 20 Fibonacci numbers."""

def fibonacci(n):
    """Generate the first n Fibonacci numbers."""
    if n <= 0:
        return []
    elif n == 1:
        return [0]

    fib_numbers = [0, 1]
    for i in range(2, n):
        fib_numbers.append(fib_numbers[i-1] + fib_numbers[i-2])

    return fib_numbers

# Generate and print the first 20 Fibonacci numbers
fib_sequence = fibonacci(20)
print(','.join(map(str, fib_sequence)))
